# player.py

from board import Board
from piece import Piece

class Player:
    def __init__(self, color):
        self.color = color

    def get_possible_moves(self, board):
        moves = []
        for row in range(8):
            for col in range(8):
                if board.board[row][col] and board.board[row][col][0] == self.color:
                    moves.extend(self.get_piece_moves(board.board[row][col], (row, col), board))
        return moves

    def get_piece_moves(self, piece, pos, board):
        row, col = pos
        moves = []

        # Check all possible directions
        directions = [(1, 1), (-1, 1), (1, -1), (-1, -1)]
        for dr, dc in directions:
            if self.is_valid_move(board, row, col, dr, dc):
                new_row, new_col = row + dr, col + dc
                moves.append(((row, col), (new_row, new_col)))

                # Check for captures
                if abs(dr) == 2 and board.board[new_row][new_col]:
                    continue

                next_dr, next_dc = dr * 2, dc * 2
                if self.is_valid_move(board, new_row, new_col, next_dr, next_dc):
                    moves.append(((row, col), (new_row + next_dr, new_col + next_dc)))

        return moves

    def is_valid_move(self, board, row, col, dr, dc):
        new_row, new_col = row + dr, col + dc
        if not (0 <= new_row < 8 and 0 <= new_col < 8):
            return False

        if board.board[new_row][new_col]:
            return False

        return True

    def make_move(self, move, board):
        from_pos, to_pos = move
        row_from, col_from = from_pos
        row_to, col_to = to_pos

        piece = board.board[row_from][col_from]
        board.board[row_to][col_to] = piece
        board.board[row_from][col_from] = ''

        # Check for kinging
        if self.color == 'b' and row_to == 7 or self.color == 'r' and row_to == 0:
            board.board[row_to][col_to].make_king()
