# game.py

from player import Player
from board import Board
from piece import Piece

class Game:
    def __init__(self):
        self.board = Board()
        self.players = {
            'b': Player('black'),
            'r': Player('red')
        }
        self.current_player = 'b'

    def switch_turn(self):
        if self.current_player == 'b':
            self.current_player = 'r'
        else:
            self.current_player = 'b'

    def check_winner(self):
        black_pieces = sum(row.count('b') for row in self.board.board)
        red_pieces = sum(row.count('r') for row in self.board.board)

        if black_pieces == 0:
            return 'red'
        elif red_pieces == 0:
            return 'black'
        else:
            return None

    def play_game(self):
        while True:
            self.board.print_board()
            moves = self.players[self.current_player].get_possible_moves(self.board)

            if not moves:
                print(f"Player {self.current_player} has no valid moves. Game over!")
                winner = 'r' if self.current_player == 'b' else 'b'
                print(f"Winner: Player {winner}")
                break

            print(f"Player {self.current_player}, enter your move (from-to):")
            from_pos, to_pos = input().split()

            if (from_pos, to_pos) in moves:
                self.players[self.current_player].make_move((from_pos, to_pos), self.board)
                winner = self.check_winner()
                if winner:
                    print(f"Winner: Player {winner}")
                    break
                self.switch_turn()
            else:
                print("Invalid move. Try again.")
